SELECT COUNT(1)
FROM HYMNS HM
WHERE HM.VISIBLE_FLG = 'true'
AND HM.NAME_JP = #{nameJp}
AND HM.ID <> #{id}

SELECT COUNT(1)
FROM HYMNS HM
WHERE HM.VISIBLE_FLG = 'true'
AND HM.NAME_KR = #{nameKr}
AND HM.ID <> #{id}

